from typing import List

class Solution:
    def canJump(self, nums: List[int]) -> bool:
        if len(nums)==1:
            return True
        r = [False]*len(nums)
        r[-1]=True
        i = len(nums)-2
        for i in range(len(nums)-2,-1,-1):
            for j in range(min(i+nums[i],len(nums)-1),i,-1):
                if r[j]==True:
                    r[i] = True
                    break
        return r[0]



